import re
import json

businesses_with_wifi = json.loads(locals()['var_function-call-16548434304143759753']['results'][0])

state_counts = {}
business_ids_by_state = {}

for business in businesses_with_wifi:
    description = business.get('description', '')
    match = re.search(r',\s*([A-Z]{2})(?:\s|\.|,|$)', description)
    if match:
        state = match.group(1)
        if state in state_counts:
            state_counts[state] += 1
            business_ids_by_state[state].append(business['business_id'])
        else:
            state_counts[state] = 1
            business_ids_by_state[state] = [business['business_id']]

most_common_state = max(state_counts, key=state_counts.get)

__RESULT__:
print(json.dumps({"most_common_state": most_common_state, "business_ids_in_state": business_ids_by_state[most_common_state]}))

